### 6. Client Pages

Remove the default Counter and Weather pages. Create these pages in `SiteInspector.Client/Pages/`:

**Home.razor** - List of inspections + start new:
```razor
@page "/"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject InspectionStorageService Storage
@inject SyncService Sync
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="app-header">
    <h1>🏗️ Site Inspector</h1>
    <div class="sync-status">
        <span class="status-dot @(Sync.IsOnline ? "online" : "offline")"></span>
        @(Sync.IsOnline ? "Online" : "Offline")
    </div>
</div>

<button class="btn-primary-large" @onclick="StartNewInspection">
    ➕ New Inspection
</button>

@if (_inspections == null)
{
    <p class="loading">Loading inspections...</p>
}
else if (_inspections.Count == 0)
{
    <div class="empty-state">
        <p>No inspections yet.</p>
        <p>Tap <strong>New Inspection</strong> to get started.</p>
    </div>
}
else
{
    <div class="inspection-list">
        @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
        {
            <div class="inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                <div class="card-header">
                    <strong>@inspection.SiteName</strong>
                    <span class="sync-badge @inspection.SyncStatus.ToString().ToLower()">
                        @GetSyncLabel(inspection.SyncStatus)
                    </span>
                </div>
                <div class="card-details">
                    <span>👷 @inspection.InspectorName</span>
                    <span>📅 @inspection.CreatedAt.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                </div>
                <div class="card-progress">
                    @{ var checked_count = inspection.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked); }
                    <span>✅ @checked_count / @inspection.ChecklistItems.Count items</span>
                    @if (inspection.Photos.Count > 0)
                    {
                        <span>📷 @inspection.Photos.Count</span>
                    }
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Inspection>? _inspections;

    protected override async Task OnInitializedAsync()
    {
        Sync.OnSyncStatusChanged += StateHasChanged;
        Sync.StartPeriodicSync();
        await LoadInspections();
    }

    private async Task LoadInspections()
    {
        _inspections = await Storage.GetAllInspectionsAsync();
    }

    private void StartNewInspection()
    {
        Nav.NavigateTo("/new-inspection");
    }

    private void OpenInspection(string id)
    {
        Nav.NavigateTo($"/inspection/{id}");
    }

    private string GetSyncLabel(SyncStatus status) => status switch
    {
        SyncStatus.Synced => "✓ Synced",
        SyncStatus.Failed => "⚠ Retry",
        _ => "● Local"
    };
}
```

**NewInspection.razor** - Form to start a new inspection:
```razor
@page "/new-inspection"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject InspectionStorageService Storage
@inject NavigationManager Nav

<PageTitle>New Inspection</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h2>New Inspection</h2>
</div>

<div class="form-group">
    <label>Site Name</label>
    <input type="text" @bind="_siteName" @bind:event="oninput" placeholder="Enter construction site name" />
</div>

<div class="form-group">
    <label>Inspector Name</label>
    <input type="text" @bind="_inspectorName" @bind:event="oninput" placeholder="Your name" />
</div>

<button class="btn-primary-large" @onclick="CreateInspection" disabled="@(!IsValid)">
    Start Inspection
</button>

@code {
    private string _siteName = "";
    private string _inspectorName = "";

    private bool IsValid => !string.IsNullOrWhiteSpace(_siteName) && !string.IsNullOrWhiteSpace(_inspectorName);

    private async Task CreateInspection()
    {
        if (!IsValid) return;

        var inspection = new Inspection
        {
            SiteName = _siteName.Trim(),
            InspectorName = _inspectorName.Trim(),
            ChecklistItems = ChecklistTemplateService.GetDefaultChecklist()
        };

        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private void GoBack() => Nav.NavigateTo("/");
}
```

**InspectionDetail.razor** - Main inspection page with tabs for checklist, notes, photos:
```razor
@page "/inspection/{InspectionId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject InspectionStorageService Storage
@inject SyncService Sync
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Inspection</PageTitle>

@if (_inspection == null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="page-header">
        <button class="btn-back" @onclick="GoBack">← Back</button>
        <h2>@_inspection.SiteName</h2>
    </div>

    <div class="tab-bar">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            ✅ Checklist
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            📝 Notes
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            📷 Photos (@_inspection.Photos.Count)
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="checklist-container">
            @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="category-group">
                    <h3 class="category-title">@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @item.Result.ToString().ToLower()">
                            <div class="item-description">@item.Description</div>
                            <div class="item-actions">
                                <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                                <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                                <button class="result-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                            </div>
                            @if (item.Result == CheckResult.Fail)
                            {
                                <input type="text" class="item-note" placeholder="Add note about failure..."
                                       value="@item.Notes" @onchange="(e) => SetItemNote(item, e.Value?.ToString() ?? "")" />
                            }
                        </div>
                    }
                </div>
            }
        </div>

        <div class="checklist-summary">
            <span>Progress: @_inspection.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked) / @_inspection.ChecklistItems.Count</span>
        </div>
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-container">
            <label>Inspection Notes</label>
            <textarea @bind="_inspection.Notes" @bind:event="oninput" @bind:after="SaveAsync"
                      placeholder="Add general observations, concerns, or comments..."
                      rows="10"></textarea>
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photos-container">
            <label class="photo-upload-btn">
                📷 Take / Add Photo
                <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" />
            </label>

            @if (_inspection.Photos.Count == 0)
            {
                <p class="empty-state">No photos yet. Tap the button above to add one.</p>
            }
            else
            {
                <div class="photo-grid">
                    @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.CapturedAt))
                    {
                        <div class="photo-card">
                            <img src="@photo.DataUrl" alt="@photo.Caption" />
                            <input type="text" placeholder="Add caption..." value="@photo.Caption"
                                   @onchange="(e) => SetPhotoCaption(photo, e.Value?.ToString() ?? "")" />
                            <button class="btn-delete" @onclick="() => RemovePhoto(photo)">🗑️ Remove</button>
                        </div>
                    }
                </div>
            }
        </div>
    }

    <div class="action-bar">
        @if (_inspection.CompletedAt == null)
        {
            <button class="btn-complete" @onclick="CompleteInspection">
                ✅ Complete Inspection
