@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? _inspection;
    private string _activeTab = "checklist";

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        await SaveAsync();
    }

    private async Task SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await SaveAsync();
    }

    private async Task SetPhotoCaption(InspectionPhoto photo, string caption)
    {
        photo.Caption = caption;
        await SaveAsync();
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        // Resize to max 1024px to save storage
        var resized = await file.RequestImageFileAsync("image/jpeg", 1024, 1024);
        using var stream = resized.OpenReadStream(maxAllowedSize: 5 * 1024 * 1024);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);
        var base64 = Convert.ToBase64String(ms.ToArray());

        var photo = new InspectionPhoto
        {
            FileName = file.Name,
            DataUrl = $"data:image/jpeg;base64,{base64}",
            CapturedAt = DateTime.UtcNow
        };

        _inspection!.Photos.Add(photo);
        await SaveAsync();
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection!.Photos.Remove(photo);
        await SaveAsync();
    }

    private async Task CompleteInspection()
    {
        _inspection!.CompletedAt = DateTime.UtcNow;
        await SaveAsync();
        await Sync.TrySyncAsync();
        StateHasChanged();
    }

    private async Task ForceSyncAsync()
    {
        await Sync.TrySyncAsync();
        _inspection = await Storage.GetInspectionAsync(InspectionId);
        StateHasChanged();
    }

    private async Task SaveAsync()
    {
        if (_inspection != null)
        {
            await Storage.SaveInspectionAsync(_inspection);
        }
    }

    private void GoBack() => Nav.NavigateTo("/");
}
```

