### 9. PWA Support

**manifest.json** in `SiteInspector/wwwroot/`:
```json
{
    "name": "Site Inspector",
    "short_name": "Inspector",
    "description": "Construction site safety inspection app",
    "start_url": "/",
    "display": "standalone",
    "background_color": "#f3f4f6",
    "theme_color": "#2563eb",
    "icons": [
        {
            "src": "icon-192.png",
            "sizes": "192x192",
            "type": "image/png"
        },
        {
            "src": "icon-512.png",
            "sizes": "512x512",
            "type": "image/png"
        }
    ]
}
```

**service-worker.js** in `SiteInspector/wwwroot/`:
```javascript
const CACHE_NAME = 'site-inspector-v1';
const OFFLINE_URLS = [
    '/',
    '/_framework/blazor.web.js'
];

self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => cache.addAll(OFFLINE_URLS))
    );
    self.skipWaiting();
});

self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys().then(keys =>
            Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
        )
    );
    self.clients.claim();
});

self.addEventListener('fetch', event => {
    // For navigation requests, try network first, fall back to cache
    if (event.request.mode === 'navigate') {
        event.respondWith(
            fetch(event.request).catch(() => caches.match('/'))
        );
        return;
    }

    // For framework files, use cache-first strategy
    if (event.request.url.includes('/_framework/')) {
        event.respondWith(
            caches.match(event.request).then(cached => {
                if (cached) return cached;
                return fetch(event.request).then(response => {
                    const clone = response.clone();
                    caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                    return response;
                });
            })
        );
        return;
    }

    // For other requests, network first with cache fallback
    event.respondWith(
        fetch(event.request).then(response => {
            if (response.ok) {
                const clone = response.clone();
                caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
            }
            return response;
        }).catch(() => caches.match(event.request))
    );
});
```

### 10. Update App.razor

Add the PWA references to `SiteInspector/Components/App.razor` in the `<head>`:
```html
<link rel="manifest" href="manifest.json" />
<meta name="theme-color" content="#2563eb" />
```

And before the closing `</body>`:
```html
<script src="js/indexedDb.js"></script>
<script>navigator.serviceWorker?.register('service-worker.js');</script>
```

Note: The `indexedDb.js` file needs to be in the SERVER project's `wwwroot/js/` since that's where static files are served from. Same for the service-worker.js and manifest.json.

### 11. Server API Endpoints

Add to `SiteInspector/Program.cs`:
```csharp
using SiteInspector.Client.Models;
using System.Collections.Concurrent;

// After existing builder.Services setup:
builder.Services.AddSingleton<ConcurrentDictionary<string, Inspection>>();

// After existing app middleware but before app.Run():
app.MapPost("/api/inspections", (Inspection inspection, ConcurrentDictionary<string, Inspection> store) =>
{
    store[inspection.Id] = inspection;
    return Results.Ok(new { success = true, id = inspection.Id });
});

app.MapGet("/api/inspections", (ConcurrentDictionary<string, Inspection> store) =>
{
    return Results.Ok(store.Values.OrderByDescending(i => i.CreatedAt));
});

app.MapGet("/api/inspections/{id}", (string id, ConcurrentDictionary<string, Inspection> store) =>
{
    return store.TryGetValue(id, out var inspection) ? Results.Ok(inspection) : Results.NotFound();
});
```

### 12. Client Program.cs 

Update `SiteInspector.Client/Program.cs`:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
