const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;
const STORE_NAME = 'inspections';

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains(STORE_NAME)) {
                database.createObjectStore(STORE_NAME, { keyPath: 'id' });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbStorage = {
    saveInspection: async function (inspection) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readwrite');
            tx.objectStore(STORE_NAME).put(inspection);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },
    getAllInspections: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const request = tx.objectStore(STORE_NAME).getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },
    getInspection: async function (id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const request = tx.objectStore(STORE_NAME).get(id);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },
    deleteInspection: async function (id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readwrite');
            tx.objectStore(STORE_NAME).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    }
};

using Microsoft.JSInterop;
using SiteInspector.Client.Models;
using System.Text.Json;

namespace SiteInspector.Client.Services;

public class InspectionStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public InspectionStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        var element = JsonSerializer.Deserialize<object>(json, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbStorage.saveInspection", element);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllInspections");
        var json = result.GetRawText();
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getInspection", id);
        if (result == null) return null;
        var json = result.Value.GetRawText();
        return JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbStorage.deleteInspection", id);
    }
}

using Microsoft.JSInterop;
using SiteInspector.Client.Models;
using System.Net.Http.Json;

namespace SiteInspector.Client.Services;

public class SyncService : IDisposable
{
    private readonly HttpClient _http;
    private readonly InspectionStorageService _storage;
    private readonly IJSRuntime _js;
    private Timer? _syncTimer;

    public event Action? OnSyncStatusChanged;
    public bool IsOnline { get; private set; } = true;

    public SyncService(HttpClient http, InspectionStorageService storage, IJSRuntime js)
    {
        _http = http;
        _storage = storage;
        _js = js;
    }

    public void StartPeriodicSync()
    {
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(30));
    }

    public async Task<bool> CheckConnectivityAsync()
    {
        try
        {
            IsOnline = await _js.InvokeAsync<bool>("eval", "navigator.onLine");
            return IsOnline;
        }
        catch
        {
            IsOnline = false;
            return false;
        }
    }

    public async Task TrySyncAsync()
    {
        if (!await CheckConnectivityAsync()) return;

        var inspections = await _storage.GetAllInspectionsAsync();
        var pending = inspections.Where(i => i.SyncStatus == SyncStatus.Pending && i.CompletedAt != null).ToList();

        foreach (var inspection in pending)
        {
            try
            {
                var response = await _http.PostAsJsonAsync("/api/inspections", inspection);
                if (response.IsSuccessStatusCode)
                {
                    inspection.SyncStatus = SyncStatus.Synced;
                    await _storage.SaveInspectionAsync(inspection);
                }
            }
            catch
            {
                inspection.SyncStatus = SyncStatus.Failed;
                await _storage.SaveInspectionAsync(inspection);
            }
        }

        OnSyncStatusChanged?.Invoke();
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
    }
}

