using SiteInspector.Client.Pages;
using SiteInspector.Client.Models;
using SiteInspector.Components;
using System.Collections.Concurrent;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddSingleton<ConcurrentDictionary<string, Inspection>>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(SiteInspector.Client._Imports).Assembly);

app.MapPost("/api/inspections", (Inspection inspection, ConcurrentDictionary<string, Inspection> store) =>
{
    store[inspection.Id] = inspection;
    return Results.Ok(new { success = true, id = inspection.Id });
});

app.MapGet("/api/inspections", (ConcurrentDictionary<string, Inspection> store) =>
{
    return Results.Ok(store.Values.OrderByDescending(i => i.CreatedAt));
});

app.MapGet("/api/inspections/{id}", (string id, ConcurrentDictionary<string, Inspection> store) =>
{
    return store.TryGetValue(id, out var inspection) ? Results.Ok(inspection) : Results.NotFound();
});

app.Run();

